{"command": "cd /root/nexa-paraguay && python3 << 'PYEOF'
import json
import os
import glob

pages_dir = 'nexa-pages'
errors = []
for fpath in sorted(glob.glob(os.path.join(pages_dir, '*.json'))):
    fname = os.path.basename(fpath)
    page_id = fname.replace('.json', '')

    with open(fpath, 'r') as f:
        data = json.load(f)

    # Check id field
    if data.get('id') != page_id:
        errors.append(f"{fname}: id field mismatch (got '{data.get('id')}', expected '{page_id}')")

    # Check sections array
    sections = data.get('sections', [])
    if not sections:
        errors.append(f"{fname}: no sections array")

    for i, section in enumerate(sections):
        if 'id' not in section:
            errors.append(f"{fname}: section[{i}] missing 'id'")
        if 'content' not in section:
            errors.append(f"{fname}: section[{i}] missing 'content'")

if errors:
    print("ERRORS:")
    for e in errors:
        print(f"  {e}")
else:
    print("All 23 configs validated successfully!")
PYEOF"}

